import React from 'react';

/* PS button symbols + colors for bullets */
const PS_BULLETS = [
  { sym: '✕', color: '#7fc5e8' },
  { sym: '○', color: '#e87b7b' },
  { sym: '□', color: '#e87bce' },
];

const AboutMe = () => {
  const items = [
    {
      label: 'Age',
      value: '19 years old',
    },
    {
      label: 'Hobbies',
      value: 'Watching anime, Working out, and Playing videogames',
      images: [
        { src: 'https://i.redd.it/both-of-these-fall-under-the-carried-by-animation-v0-gjip3tvumfpe1.jpg?width=680&format=pjpg&auto=webp&s=9ccf13e4c652abbe24cec0618bc0849a23e3c699', alt: 'Anime' },
        { src: 'https://img.joomcdn.net/3951999955bde0c8ac0a989a3d481890d9b794cd_original.jpeg', alt: 'Bodybuilding' },
        { src: 'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcQ0WSAO7K7N54BRF4t5rcez6eaZuHPYT88DMA&s', alt: 'Videogame' },
      ],
    },
    {
      label: 'Interest',
      value: 'Bodybuilding, Anime, Kdrama, and Alternative R&B',
      images: [
        { src: 'https://st2.depositphotos.com/5894210/11673/v/450/depositphotos_116738402-stock-illustration-vector-illustration-of-bodybuilder-on.jpg', alt: 'Bodybuilding' },
        { src: 'https://i.redd.it/both-of-these-fall-under-the-carried-by-animation-v0-gjip3tvumfpe1.jpg?width=680&format=pjpg&auto=webp&s=9ccf13e4c652abbe24cec0618bc0849a23e3c699', alt: 'Anime' },
        { src: 'https://preview.redd.it/netflix-the-glory-part-2-character-poster-premieres-march-10-v0-0fnd9a1r92ha1.jpg?width=640&crop=smart&auto=webp&s=d2764e951ec3de50b867f34db2cd1c6e68cb625c', alt: 'Kdrama' },
        { src: 'https://m.media-amazon.com/images/I/71LIeQ11qqL._AC_UF894,1000_QL80_.jpg', alt: 'R&B' },
      ],
    },
  ];

  return (
    <section
      id="About-Me"
      className="min-h-screen flex flex-col justify-center items-center px-5 py-24"
      style={{ background: 'var(--ps-navy, #0a0f2e)' }}
    >
      <h1 className="ps-title font-bold text-4xl text-white text-center mb-12">More About Me</h1>

      <div className="w-full max-w-3xl flex flex-col gap-6">
        {items.map((item, i) => {
          const { sym, color } = PS_BULLETS[i % PS_BULLETS.length];
          return (
            <div
              key={i}
              className="rounded-xl p-6"
              style={{
                background: 'rgba(0,55,145,0.12)',
                border: '1px solid rgba(0,112,204,0.3)',
              }}
            >
              <div className="flex items-start gap-3">
                <span style={{ color, fontSize: '18px', marginTop: '2px', flexShrink: 0 }}>{sym}</span>
                <div>
                  <p className="text-white text-base">
                    <b style={{ color }}>{item.label}:</b>{' '}
                    <i style={{ color: 'rgba(255,255,255,0.8)' }}>{item.value}</i>
                  </p>
                  {item.images && (
                    <div className="flex justify-start gap-4 mt-4 flex-wrap">
                      {item.images.map((img, j) => (
                        <img
                          key={j}
                          src={img.src}
                          alt={img.alt}
                          width="140"
                          className="rounded-lg"
                          style={{ border: `1px solid ${color}44` }}
                        />
                      ))}
                    </div>
                  )}
                </div>
              </div>
            </div>
          );
        })}
      </div>
    </section>
  );
};

export default AboutMe;
